CREATE TABLE IF NOT EXISTS hijaiyah_letters (
    id              VARCHAR(50)  PRIMARY KEY,
    arabic          VARCHAR(10)  NOT NULL,
    name            VARCHAR(50)  NOT NULL,
    transliteration VARCHAR(10)  NOT NULL,
    pronunciation   VARCHAR(50)  NOT NULL,
    audio_url       VARCHAR(500),
    sort_order      INT          NOT NULL DEFAULT 0,
    description     TEXT,
    writing_steps   JSONB        NOT NULL DEFAULT '[]',
    stroke_points   JSONB        NOT NULL DEFAULT '[]',
    created_at      TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS quiz_categories (
    id          VARCHAR(50)  PRIMARY KEY,
    name        VARCHAR(100) NOT NULL,
    description TEXT         NOT NULL,
    icon        VARCHAR(50)  NOT NULL,
    color       VARCHAR(50)  NOT NULL,
    created_at  TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS quiz_questions (
    id             VARCHAR(50)  PRIMARY KEY,
    question       TEXT         NOT NULL,
    options        JSONB        NOT NULL DEFAULT '[]',
    correct_answer INT          NOT NULL,
    explanation    TEXT         NOT NULL,
    material       TEXT         NOT NULL,
    category_id    VARCHAR(50)  NOT NULL REFERENCES quiz_categories(id) ON DELETE CASCADE,
    difficulty     VARCHAR(10)  NOT NULL CHECK (difficulty IN ('easy','medium','hard')),
    created_at     TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    updated_at     TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS quran_surahs (
    id               INT          PRIMARY KEY,
    name             VARCHAR(100) NOT NULL,
    arabic_name      VARCHAR(200) NOT NULL,
    english_name     VARCHAR(200) NOT NULL,
    number_of_ayahs  INT          NOT NULL,
    revelation_type  VARCHAR(10)  NOT NULL CHECK (revelation_type IN ('Meccan','Medinan')),
    audio_url        VARCHAR(500),
    created_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    updated_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_hijaiyah_sort_order     ON hijaiyah_letters (sort_order);
CREATE INDEX IF NOT EXISTS idx_quiz_questions_category ON quiz_questions (category_id);
CREATE INDEX IF NOT EXISTS idx_quiz_questions_diff     ON quiz_questions (difficulty);

-- ===================== SEED DATA =====================

DELETE FROM quiz_questions;
DELETE FROM quiz_categories;
DELETE FROM hijaiyah_letters;
DELETE FROM quran_surahs;

