-- ==================== QUIZ QUESTIONS ====================

-- Hijaiyah
('h1',  'Huruf apakah ini: ب',                                                                       '["Alif","Ba","Ta","Tsa"]',                                                                                                    1, 'Huruf ب dibaca ''Ba'' dan merupakan huruf kedua dalam alfabet Arab.',                                                                                                                                        'Huruf Ba (ب) adalah huruf kedua dalam alfabet Arab. Huruf ini memiliki satu titik di bawah. Dalam pengucapannya, kedua bibir dirapatkan.',                                                                              'hijaiyah', 'easy'),
('h2',  'Berapa jumlah huruf Hijaiyah?',                                                             '["26","27","28","29"]',                                                                                                       2, 'Huruf Hijaiyah berjumlah 28 huruf, dari Alif hingga Ya.',                                                                                                                                                  'Huruf Hijaiyah adalah sistem alfabet yang digunakan dalam bahasa Arab dan Al-Qur''an. Secara umum, jumlah huruf dasar Hijaiyah adalah 28 huruf.',                                                                       'hijaiyah', 'easy'),
('h3',  'Huruf mana yang memiliki 3 titik di atas?',                                                 '["ت","ث","ج","خ"]',                                                                                                           1, 'Huruf ث (Tsa) memiliki 3 titik di atas, sedangkan ت (Ta) memiliki 2 titik.',                                                                                                                               'Beberapa huruf hijaiyah memiliki bentuk yang mirip namun dibedakan oleh titik. Huruf Ta (ت) punya 2 titik di atas, sedangkan Tsa (ث) punya 3 titik di atas.',                                                         'hijaiyah', 'medium'),
('h4',  'Huruf apakah ini: ج',                                                                       '["Ha","Kho","Jim","Dal"]',                                                                                                    2, 'Huruf ج dibaca ''Jim''.',                                                                                                                                                                                   'Huruf Jim (ج) memiliki satu titik di tengah perutnya. Pengucapannya keluar dari tengah lidah yang bertemu dengan langit-langit mulut.',                                                                                 'hijaiyah', 'easy'),
('h5',  'Manakah huruf ''Kho''?',                                                                    '["ح","خ","ج","ع"]',                                                                                                           1, 'Huruf خ adalah ''Kho''.',                                                                                                                                                                                   'Huruf Kho (خ) memiliki titik di atas kepalanya. Suaranya terdengar seperti suara ''ngorok'' halus yang keluar dari tenggorokan bagian atas.',                                                                           'hijaiyah', 'easy'),
('h6',  'Huruf ''Dal'' adalah...',                                                                   '["د","ذ","ر","ز"]',                                                                                                           0, 'Huruf د adalah ''Dal''.',                                                                                                                                                                                   'Huruf Dal (د) tidak memiliki titik. Pengucapannya dengan menyentuhkan ujung lidah ke pangkal gigi seri bagian atas.',                                                                                                  'hijaiyah', 'easy'),
('h7',  'Huruf ''Ra'' memiliki bentuk yang mirip dengan...',                                         '["Dal","Zain","Sin","Lam"]',                                                                                                  1, 'Ra (ر) mirip dengan Zain (ز).',                                                                                                                                                                            'Huruf Ra (ر) dan Zain (ز) memiliki bentuk yang sama, namun Zain memiliki satu titik di atasnya.',                                                                                                                       'hijaiyah', 'easy'),
('h8',  'Huruf Sin (س) memiliki berapa lekukan kecil di atasnya?',                                  '["1","2","3","4"]',                                                                                                           1, 'Sin memiliki 2 lekukan kecil di awal.',                                                                                                                                                                    'Huruf Sin (س) memiliki dua lekukan kecil dan satu lekukan besar di bawahnya. Sin tidak memiliki titik.',                                                                                                               'hijaiyah', 'medium'),
('h9',  'Manakah huruf Shad?',                                                                       '["س","ش","ص","ض"]',                                                                                                           2, 'Huruf ص adalah Shad.',                                                                                                                                                                                     'Huruf Shad (ص) diucapkan dengan suara desis yang kuat dan posisi lidah yang naik ke langit-langit (tebal).',                                                                                                           'hijaiyah', 'medium'),
('h10', 'Huruf yang diucapkan dengan ujung lidah menyentuh ujung gigi seri atas dan terdengar lembut adalah...', '["ت","ث","س","ص"]',                                                                                    1, 'Huruf ث (Tsa) diucapkan dengan ujung lidah.',                                                                                                                                                              'Huruf Tsa (ث) diucapkan dengan mengeluarkan sedikit ujung lidah di antara gigi seri atas dan bawah.',                                                                                                                   'hijaiyah', 'hard'),
-- Tajwid
('t1',  'Apa yang dimaksud dengan Tajwid?',                                                          '["Membaca Al-Qur''an dengan cepat","Membaca Al-Qur''an dengan benar sesuai kaidah","Menghafal Al-Qur''an","Menulis Al-Qur''an"]', 1, 'Tajwid adalah ilmu yang mempelajari cara membaca Al-Qur''an dengan benar sesuai kaidah yang telah ditetapkan.',                                                                                              'Secara bahasa, Tajwid berarti memperindah atau melakukan dengan baik. Dalam ilmu Al-Qur''an, Tajwid adalah ilmu untuk membaca Al-Qur''an dengan benar sesuai makhraj dan sifat hurufnya.',                              'tajwid',   'easy'),
('t2',  'Berapa panjang bacaan Mad Thobi''i?',                                                       '["1 harakat","2 harakat","4 harakat","6 harakat"]',                                                                            1, 'Mad Thobi''i dibaca sepanjang 2 harakat atau 2 ketukan.',                                                                                                                                                  'Mad Thobi''i atau Mad Ashli terjadi apabila ada Alif setelah fathah, Wawu sukun setelah dhommah, atau Ya sukun setelah kasroh. Panjangnya adalah 2 harakat.',                                                           'tajwid',   'medium'),
('t3',  'Hukum Nun Sukun bertemu dengan huruf ''Ba'' disebut...',                                    '["Izhari","Idgham","Iqlab","Ikhfa"]',                                                                                          2, 'Iqlab adalah mengganti suara Nun menjadi Mim saat bertemu Ba.',                                                                                                                                             'Iqlab secara bahasa berarti mengganti. Dalam tajwid, Iqlab terjadi jika Nun sukun atau Tanwin bertemu huruf Ba (ب), suaranya diganti menjadi Mim disertai dengung.',                                                    'tajwid',   'medium'),
('t4',  'Huruf-huruf Qolqolah terkumpul dalam kalimat...',                                           '["يَرْمَلُوْن","قُطْبُ جَدٍ","أَبْغِ حَجَّكَ","ءي"]',                                                                         1, 'Huruf Qolqolah adalah Qaf, Tha, Ba, Jim, Dal.',                                                                                                                                                           'Qolqolah berarti pantulan. Hurufnya ada 5: Qaf, Tha, Ba, Jim, Dal (ق، ط، ب، ج، د), yang sering disingkat ''Qutbu Jadin''.',                                                                                              'tajwid',   'medium'),
('t5',  'Apa arti dari ''Izhari''?',                                                                 '["Samar","Jelas","Memasukkan","Memantul"]',                                                                                    1, 'Izhar berarti dibaca dengan jelas tanpa dengung.',                                                                                                                                                         'Izhar secara bahasa berarti jelas. Dalam tajwid, Izhar Halqi terjadi jika Nun sukun atau Tanwin bertemu salah satu huruf tenggorokan (ء، هـ، ع، ح، غ، خ).',                                                              'tajwid',   'easy'),
('t6',  'Berapakah jumlah huruf Ikhfa Haqiqi?',                                                     '["5","10","15","20"]',                                                                                                        2, 'Ada 15 huruf Ikhfa Haqiqi.',                                                                                                                                                                               'Ikhfa berarti menyamarkan. Huruf Ikhfa Haqiqi berjumlah 15 huruf, yaitu selain huruf Izhar, Iqlab, dan Idgham.',                                                                                                       'tajwid',   'hard'),
('t7',  'Ghunnah artinya...',                                                                        '["Jelas","Dengung","Panjang","Pendek"]',                                                                                       1, 'Ghunnah adalah suara mendengung.',                                                                                                                                                                         'Ghunnah adalah suara yang keluar dari pangkal hidung. Hukum ini wajib dibaca pada Nun dan Mim yang bertasydid (نّ dan مّ).',                                                                                             'tajwid',   'easy'),
('t8',  'Hukum Alif Lam yang dibaca jelas disebut...',                                               '["Alif Lam Syamsiyah","Alif Lam Qomariyah","Alif Lam Ma''rifah","Alif Lam Nakirah"]',                                          1, 'Alif Lam Qomariyah dibaca jelas.',                                                                                                                                                                         'Alif Lam Qomariyah adalah hukum membaca Alif Lam secara jelas (Idzhar) ketika bertemu dengan 14 huruf tertentu.',                                                                                                       'tajwid',   'medium'),
('t9',  'Mad yang terjadi di akhir ayat karena waqof disebut...',                                    '["Mad Thobi''i","Mad Wajib Muttasil","Mad Arid Lissukun","Mad Jaiz Munfasil"]',                                                2, 'Mad Arid Lissukun terjadi karena waqof.',                                                                                                                                                                  'Mad Arid Lissukun terjadi jika ada Mad Thobi''i bertemu huruf hidup di akhir ayat atau tempat waqof. Panjangnya bisa 2, 4, atau 6 harakat.',                                                                            'tajwid',   'hard'),
('t10', 'Idgham Bighunnah artinya memasukkan suara dengan...',                                       '["Jelas","Dengung","Tanpa Dengung","Cepat"]',                                                                                  1, 'Idgham Bighunnah disertai dengan dengung.',                                                                                                                                                                'Idgham Bighunnah terjadi jika Nun sukun atau Tanwin bertemu huruf Ya, Nun, Mim, Wawu (ي، ن، م، و). Dibaca dengan memasukkan suara dan mendengung.',                                                                      'tajwid',   'medium'),
-- Worship
('w1',  'Berapa rakaat shalat Maghrib?',                                                             '["2 rakaat","3 rakaat","4 rakaat","5 rakaat"]',                                                                                1, 'Shalat Maghrib adalah 3 rakaat, terdiri dari 2 rakaat sirr dan 1 rakaat jahr.',                                                                                                                             'Shalat fardhu lima waktu memiliki jumlah rakaat yang berbeda: Subuh (2), Dhuhur (4), Ashar (4), Maghrib (3), dan Isya (4).',                                                                                             'worship',  'easy'),
('w2',  'Kapan waktu shalat Dhuha?',                                                                 '["Setelah terbit matahari hingga sebelum Dhuhur","Setelah Maghrib hingga Isya","Setelah Isya hingga Subuh","Setelah Subuh hingga terbit matahari"]', 0, 'Shalat Dhuha dilakukan setelah matahari terbit (naik setinggi tombak) hingga sebelum masuk waktu Dhuhur.', 'Shalat Dhuha adalah shalat sunnah yang dilakukan di pagi hari. Waktunya dimulai saat matahari mulai meninggi (sekitar 15 menit setelah terbit) hingga mendekati waktu Dhuhur.',                                          'worship',  'medium'),
('w3',  'Rukun Islam yang pertama adalah...',                                                        '["Shalat","Zakat","Syahadat","Puasa"]',                                                                                        2, 'Syahadat adalah rukun Islam yang pertama.',                                                                                                                                                                'Islam dibangun di atas lima rukun: Syahadat, Shalat, Zakat, Puasa, dan Haji bagi yang mampu.',                                                                                                                         'worship',  'easy'),
('w4',  'Membasuh muka dalam wudhu hukumnya...',                                                     '["Sunnah","Wajib/Rukun","Makruh","Mubah"]',                                                                                    1, 'Membasuh muka adalah salah satu rukun wudhu.',                                                                                                                                                             'Rukun wudhu ada enam: Niat, membasuh wajah, membasuh kedua tangan hingga siku, mengusap sebagian kepala, membasuh kedua kaki hingga mata kaki, dan tertib.',                                                            'worship',  'easy'),
('w5',  'Apa rukun iman yang ketiga?',                                                               '["Iman kepada Allah","Iman kepada Malaikat","Iman kepada Kitab-kitab","Iman kepada Rasul"]',                                    2, 'Beriman kepada Kitab-kitab Allah adalah rukun iman ketiga.',                                                                                                                                               'Rukun Iman ada enam: Beriman kepada Allah, Malaikat, Kitab-kitab-Nya, para Rasul-Nya, Hari Akhir, serta Qada dan Qadar.',                                                                                               'worship',  'medium'),
('w6',  'Puasa Ramadan hukumnya...',                                                                 '["Sunnah","Mubah","Wajib","Haram"]',                                                                                           2, 'Puasa Ramadan wajib bagi umat Muslim.',                                                                                                                                                                    'Puasa Ramadan adalah salah satu kewajiban bagi setiap Muslim yang sudah baligh, berakal, dan mampu melakukannya.',                                                                                                       'worship',  'easy'),
('w7',  'Arah kiblat umat Islam saat shalat adalah...',                                              '["Baitul Maqdis","Masjid Nabawi","Ka''bah","Masjid Quba"]',                                                                     2, 'Ka''bah adalah kiblat umat Islam.',                                                                                                                                                                         'Setiap Muslim wajib menghadap ke Ka''bah di Makkah (Al-Masjid Al-Haram) saat melaksanakan shalat.',                                                                                                                     'worship',  'easy'),
('w8',  'Berapakah jumlah zakat fitrah yang harus dikeluarkan per orang?',                           '["1 kg beras","2,5 kg atau 3,5 liter beras","5 kg beras","10 kg beras"]',                                                      1, 'Zakat fitrah setara dengan 2,5 kg atau 3,5 liter beras.',                                                                                                                                                  'Zakat fitrah wajib dikeluarkan di akhir Ramadan sebesar satu sha'' makanan pokok, yang setara dengan sekitar 2,5 kg atau 3,5 liter beras.',                                                                             'worship',  'medium'),
('w9',  'Mengusap telinga saat wudhu hukumnya...',                                                   '["Wajib","Sunnah","Haram","Makruh"]',                                                                                          1, 'Mengusap telinga adalah sunnah wudhu.',                                                                                                                                                                    'Dalam wudhu, terdapat rukun yang wajib dilakukan dan sunnah yang jika dilakukan menambah pahala, seperti mengusap telinga.',                                                                                            'worship',  'medium'),
('w10', 'Shalat sunnah yang mengiringi shalat fardhu disebut shalat...',                             '["Tahajjud","Witir","Rawatib","Istikharah"]',                                                                                   2, 'Shalat Rawatib adalah pendamping shalat fardhu.',                                                                                                                                                         'Shalat sunnah Rawatib adalah shalat yang dilakukan sebelum (Qobliyah) atau sesudah (Ba''diyyah) shalat fardhu.',                                                                                                         'worship',  'medium'),
-- General
('g1',  'Berapa jumlah surah dalam Al-Qur''an?',                                                     '["112","113","114","115"]',                                                                                                    2, 'Al-Qur''an terdiri dari 114 surah, dimulai dari Al-Fatihah hingga An-Nas.',                                                                                                                                'Al-Qur''an diturunkan secara bertahap kepada Nabi Muhammad SAW. Kitab suci ini terbagi menjadi 30 Juz dan terdiri dari 114 Surah.',                                                                                     'general',  'easy'),
('g2',  'Siapa nama malaikat yang bertugas menyampaikan wahyu?',                                     '["Mikail","Jibril","Israfil","Ridwan"]',                                                                                        1, 'Malaikat Jibril (Gabriel) adalah malaikat yang bertugas menyampaikan wahyu dari Allah kepada para nabi.',                                                                                                  'Beriman kepada malaikat adalah rukun iman kedua. Setiap malaikat memiliki tugas khusus, seperti Jibril pembawa wahyu dan Mikail pembagi rezeki.',                                                                       'general',  'easy'),
('g3',  'Di kota mana Nabi Muhammad SAW lahir?',                                                     '["Madinah","Thaif","Makkah","Badar"]',                                                                                         2, 'Nabi Muhammad SAW lahir di kota Makkah pada tahun 571 Masehi (Tahun Gajah).',                                                                                                                              'Nabi Muhammad SAW lahir pada hari Senin, 12 Rabiul Awal tahun Gajah. Beliau dilahirkan di Makkah, sebuah kota suci di Jazirah Arab.',                                                                                  'general',  'easy'),
('g4',  'Apa nama kitab yang diturunkan kepada Nabi Daud AS?',                                       '["Taurat","Zabur","Injil","Al-Qur''an"]',                                                                                       1, 'Nabi Daud AS menerima kitab Zabur.',                                                                                                                                                                       'Allah menurunkan kitab-kitab kepada para rasul: Taurat (Musa), Zabur (Daud), Injil (Isa), dan Al-Qur''an (Muhammad).',                                                                                                  'general',  'medium'),
('g5',  'Siapakah nama ayah Nabi Muhammad SAW?',                                                     '["Abu Thalib","Abdul Muthalib","Abdullah","Hamzah"]',                                                                          2, 'Ayah Nabi Muhammad adalah Abdullah.',                                                                                                                                                                      'Nabi Muhammad SAW adalah putra dari pasangan Abdullah bin Abdul Muthalib dan Aminah binti Wahb.',                                                                                                                       'general',  'easy'),
('g6',  'Siapakah wanita pertama yang memeluk Islam?',                                               '["Aisyah","Fathimah","Khadijah","Sumayyah"]',                                                                                  2, 'Khadijah adalah orang pertama yang masuk Islam.',                                                                                                                                                         'Istri pertama Nabi Muhammad SAW, Khadijah binti Khuwailid, adalah orang pertama yang beriman dan mendukung dakwah beliau.',                                                                                              'general',  'medium'),
('g7',  'Apa nama bulan pertama dalam kalender Hijriah?',                                            '["Ramadan","Muharram","Syawal","Zulhijjah"]',                                                                                  1, 'Muharram adalah bulan pertama tahun Hijriah.',                                                                                                                                                             'Kalender Islam (Hijriah) terdiri dari 12 bulan, dimulai dari Muharram dan diakhiri dengan Zulhijjah.',                                                                                                                  'general',  'easy'),
('g8',  'Peristiwa perjalanan Nabi Muhammad dari Makkah ke Baitul Maqdis lalu ke langit disebut...', '["Hijrah","Isra Mi''raj","Fathu Makkah","Haji Wada"]',                                                                          1, 'Peristiwa itu disebut Isra Mi''raj.',                                                                                                                                                                       'Isra Mi''raj adalah mukjizat besar di mana Nabi Muhammad SAW diperjalankan dalam satu malam dan menerima perintah shalat lima waktu.',                                                                                   'general',  'medium'),
('g9',  'Siapakah sahabat Nabi yang dijuluki ''Al-Faruq''?',                                         '["Abu Bakar Ash-Shiddiq","Umar bin Khattab","Utsman bin Affan","Ali bin Abi Thalib"]',                                          1, 'Umar bin Khattab dijuluki Al-Faruq.',                                                                                                                                                                     'Umar bin Khattab dikenal karena ketegasannya dalam membedakan yang haq (benar) dan yang bathil (salah), sehingga dijuluki Al-Faruq.',                                                                                    'general',  'hard'),
('g10', 'Surah terpanjang dalam Al-Qur''an adalah...',                                               '["Ali Imran","An-Nisa","Al-Maidah","Al-Baqarah"]',                                                                             3, 'Al-Baqarah adalah surah terpanjang.',                                                                                                                                                                     'Surah Al-Baqarah adalah surah kedua dalam Al-Qur''an dan merupakan surah terpanjang dengan jumlah 286 ayat.',                                                                                                           'general',  'medium');

-- ==================== QURAN SURAHS ====================

